// 1. Interface ilə sadə object type
interface Product {
  name: string;
  price: number;
}
const laptop: Product = { name: "Laptop", price: 1200 };
// laptop.price = "1000"; // Xəta: string number tipinə uyğun deyil

// 2. Type ilə object type
type User = {
  name: string;
  age: number;
  isActive?: boolean; // Opsiyonel xüsusiyyət
};
const user1: User = { name: "Murad", age: 23 }; // isActive olmadan işləyir
const user2: User = { name: "Alice", age: 25, isActive: true };

// 3. Readonly xüsusiyyətlər
interface Book {
  readonly title: string;
  pages: number;
}
const book: Book = { title: "TypeScript Guide", pages: 200 };
// book.title = "New Title"; // Xəta: readonly xüsusiyyət dəyişdirilə bilməz

// 4. Funksiyalarda object types
function showProduct(product: Product): string {
  return `${product.name}: $${product.price}`;
}
console.log(showProduct(laptop)); // Çıxış: Laptop: $1200

// 5. Opsiyonel xüsusiyyətlər ilə mürəkkəb obyekt
type Order = {
  id: string;
  total: number;
  status?: "pending" | "shipped"; // Opsiyonel və literal type
};
const order: Order = { id: "A123", total: 50 }; // status olmadan işləyir

// 6. İç-içə obyektlər
interface Address {
  city: string;
  postalCode: string;
}
interface Customer {
  name: string;
  address: Address;
}
const customer: Customer = {
  name: "Murad",
  address: { city: "Baku", postalCode: "AZ1000" }
};
console.log(`${customer.name}, ${customer.address.city}`); // Çıxış: Murad, Baku

// Sadə mağaza sistemi
interface Product {
  id: string;
  name: string;
  price: number;
  inStock?: boolean; // Opsiyonel
}

function displayProduct(product: Product): string {
  const stockStatus = product.inStock !== undefined ? (product.inStock ? "mövcuddur" : "mövcud deyil") : "məlumat yoxdur";
  return `${product.name} (ID: ${product.id}): $${product.price}, ${stockStatus}`;
}

const laptop: Product = { id: "P001", name: "Laptop", price: 1200, inStock: true };
const mouse: Product = { id: "P002", name: "Mouse", price: 25 };

console.log(displayProduct(laptop)); // Çıxış: Laptop (ID: P001): $1200, mövcuddur
console.log(displayProduct(mouse)); // Çıxış: Mouse (ID: P002): $25, məlumat yoxdur

// Readonly ilə sabit məlumat
interface Category {
  readonly name: string;
  description: string;
}
const category: Category = { name: "Electronics", description: "Tech products" };
// category.name = "Books"; // Xəta: readonly xüsusiyyət dəyişdirilə bilməz

