// 1. Simple object type with interface
interface Product {
  name: string;
  price: number;
}
const laptop: Product = { name: "Laptop", price: 1200 };
// laptop.price = "1000"; // Error: string is not number type

// 2. Object type with type
type User = {
  name: string;
  age: number;
  isActive?: boolean; // Optional property
};
const user1: User = { name: "Murad", age: 23 }; // Works without isActive
const user2: User = { name: "Alice", age: 25, isActive: true };

// 3. Readonly properties
interface Book {
  readonly title: string;
  pages: number;
}
const book: Book = { title: "TypeScript Guide", pages: 200 };
// book.title = "New Title"; // Error: readonly property cannot be modified

// 4. Object types in functions
function showProduct(product: Product): string {
  return `${product.name}: $${product.price}`;
}
console.log(showProduct(laptop)); // Output: Laptop: $1200

// 5. Optional properties with complex object
type Order = {
  id: string;
  total: number;
  status?: "pending" | "shipped"; // Optional and literal type
};
const order: Order = { id: "A123", total: 50 }; // Works without status

// 6. Nested objects
interface Address {
  city: string;
  postalCode: string;
}
interface Customer {
  name: string;
  address: Address;
}
const customer: Customer = {
  name: "Murad",
  address: { city: "Baku", postalCode: "AZ1000" }
};
console.log(`${customer.name}, ${customer.address.city}`); // Output: Murad, Baku

// Simple store system
interface Product {
  id: string;
  name: string;
  price: number;
  inStock?: boolean; // Optional
}

function displayProduct(product: Product): string {
  const stockStatus = product.inStock !== undefined ? (product.inStock ? "in stock" : "out of stock") : "no info";
  return `${product.name} (ID: ${product.id}): $${product.price}, ${stockStatus}`;
}

const laptop: Product = { id: "P001", name: "Laptop", price: 1200, inStock: true };
const mouse: Product = { id: "P002", name: "Mouse", price: 25 };

console.log(displayProduct(laptop)); // Output: Laptop (ID: P001): $1200, in stock
console.log(displayProduct(mouse)); // Output: Mouse (ID: P002): $25, no info

// Readonly for fixed data
interface Category {
  readonly name: string;
  description: string;
}
const category: Category = { name: "Electronics", description: "Tech products" };
// category.name = "Books"; // Error: readonly property cannot be modified

